oldWay:
/* JavaScript scroll listener calculating snap positions */
container.addEventListener('scroll', () => {
  const cardWidth = card.offsetWidth + gap;
  const nearest = Math.round(container.scrollLeft / cardWidth);
  container.scrollTo({
    left: nearest * cardWidth,
    behavior: 'smooth'
  });
});

modernWay:
.container {
  scroll-snap-type: x mandatory;
  overflow-x: auto;
}
.card {
  scroll-snap-align: start;
}

